    },
    {
      "path": "templates/dashboard.html",
      "content": "{% extends 'base.html' %}
{% block content %}
\<div class='grid grid-cols-1 md:grid-cols-3 gap-6 mb-10'\>
    {% for budget in budgets %}
    \<div class='bg-white p-6 rounded-3xl shadow-sm border border-slate-200'\>
        \<h3 class='text-xs text-slate-400 font-bold uppercase mb-2'\>{{ budget.name }}\</h3\>
        \<div class='text-3xl font-black mb-4'\>${{ budget.actual }} \<span class='text-sm font-medium text-slate-300'\>/ ${{ budget.target }}</span></div>
        <div class='w-full bg-slate-100 h-2 rounded-full overflow-hidden'>
            <div class='bg-emerald-500 h-full' style='width: {{ (budget.actual/budget.target*100)|round }}%'></div>
        </div>
    </div>
    {% endfor %}
</div>
<div class='grid grid-cols-1 lg:grid-cols-2 gap-8'>
    <div class='bg-white p-8 rounded-3xl shadow-sm border border-slate-200'>
        <h3 class='font-bold text-xl mb-6'>Spending Analysis</h3>
        <canvas id='expenseChart' height='250'></canvas>
    </div>
    <div class='space-y-4'>
        <h3 class='font-bold text-xl px-2 mb-4'>Financial Alerts</h3>
        {% for alert in alerts %}
        <div class='bg-amber-50 border border-amber-100 p-5 rounded-2xl flex gap-4 items-center'>
            <div class='w-10 h-10 bg-amber-500 rounded-full flex-shrink-0'></div>
            <div>
                <p class='text-xs font-bold text-amber-600 uppercase mb-0.5'>{{ alert.type }}</p>
                <p class='text-sm text-amber-900 leading-tight'>{{ alert.message }}</p>
            </div>
        </div>
        {% endfor %}
    </div>
</div>
<script>
    const ctx = document.getElementById('expenseChart').getContext('2d');
    new Chart(ctx, {
        type: 'line',
        data: { 
            labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'], 
            datasets: [{
                label: 'Expenses',
                data: [120, 190, 80, 50, 220, 300, 170], 
                borderColor: '#10b981', 
                backgroundColor: 'rgba(16, 185, 129, 0.1)',
                fill: true,
                tension: 0.4 
            }] 
        },
        options: { plugins: { legend: { display: false } }, scales: { y: { beginAtZero: true } } }
    });
</script>
{% endblock %}\

